## 2. DATABASE ABSTRACTION LAYER (src/utils/database.ts)

### Pattern Overview:
The database module uses an abstraction pattern supporting both Tauri (SQLite) and web (localStorage):

```typescript
export interface TableRow {
  id: string;
  [fields]: string;  // All stored as strings, converted to proper types at layer boundary
  created_at: string;  // ISO format
  updated_at: string;
}

export const dbObject = {
  async getAll(): Promise<TableRow[]> {
    if (isTauri) {
      const db = await getDb();
      return db.select<TableRow[]>('SELECT ... FROM table ORDER BY ...');
    }
    return storageGet('localStorage-key', isRowArray) ?? [];
  },

  async insert(row: TableRow): Promise<void> {
    if (isTauri) {
      const db = await getDb();
      await db.execute('INSERT INTO table (...) VALUES (...)', [values]);
    }
    const all = await this.getAll();
    all.unshift(row);
    storageSet('localStorage-key', all);
  },

  async update(id: string, updates: Partial<Omit<TableRow, 'id'>>): Promise<void> {
    if (isTauri) {
      const db = await getDb();
      const query = buildUpdateQuery('table', updates, ALLOWED_COLUMNS, id);
      if (!query) return;
      await db.execute(query.sql, query.values);
    }
    const all = await this.getAll();
    const updated = all.map(r => (r.id === id ? { ...r, ...updates } : r));
    storageSet('localStorage-key', updated);
  },

  async delete(id: string): Promise<void> {
    if (isTauri) {
      const db = await getDb();
      await db.execute('DELETE FROM table WHERE id = $1', [id]);
    }
    const all = await this.getAll();
    storageSet('localStorage-key', all.filter(r => r.id !== id));
  },

  async search(query: string, limit = 50): Promise<TableRow[]> {
    if (isTauri) {
      // Use FTS5 or LIKE queries
      const db = await getDb();
      return db.select<TableRow[]>('SELECT ... FROM table WHERE ...');
    }
    const all = await this.getAll();
    return all.filter(/* fuzzy match logic */).slice(0, limit);
  },
};

// Type guard function
function isRowArray(v: unknown): v is TableRow[] {
  if (!Array.isArray(v)) return false;
  return v.every(r => typeof r === 'object' && r !== null && 'id' in r && 'title' in r);
}

// Update column allowlist
const ALLOWED_COLUMNS = new Set<string>(['title', 'other', 'fields']);
```

### For Reminders Database (reminders_data.ts equivalent for db.ts):
You'll add to `src/utils/database.ts`:

