## 4. FORM COMPONENT PATTERNS (src/components/form/)

### Individual Form Field Components:

**FormField (wrapper for all form fields):**
```typescript
interface FormFieldProps {
  label: string;
  description?: string;
  error?: string;
  children: ReactNode;
  htmlFor?: string;
}

export function FormField({ label, description, error, children, htmlFor }: FormFieldProps) {
  return (
    <div className={`form-field${error ? ' form-field--error' : ''}`}>
      <div className="form-field__header">
        <label className="form-field__label" htmlFor={htmlFor}>{label}</label>
        {error && <span className="form-field__error">{error}</span>}
        {!error && description && <span className="form-field__description">{description}</span>}
      </div>
      <div className="form-field__control">{children}</div>
    </div>
  );
}
```

**FormTextField:**
```typescript
interface FormTextFieldProps {
  label: string;
  value: string;
  onChange: (value: string) => void;
  placeholder?: string;
  description?: string;
  error?: string;
  autoFocus?: boolean;
}
```

**FormTextArea:**
```typescript
interface FormTextAreaProps {
  label: string;
  value: string;
  onChange: (value: string) => void;
  placeholder?: string;
  description?: string;
  error?: string;
  rows?: number;
}
```

**FormDatePicker:**
```typescript
interface FormDatePickerProps {
  label: string;
  value: string;  // ISO format 'YYYY-MM-DD'
  onChange: (value: string) => void;
  description?: string;
  error?: string;
  includeTime?: boolean;  // Use datetime-local if true
  min?: string;
  max?: string;
}

export function FormDatePicker({ label, value, onChange, description, error, includeTime, min, max }: FormDatePickerProps) {
  const id = useId();
  return (
    <FormField label={label} description={description} error={error} htmlFor={id}>
      <input
        id={id}
        className="form-input form-input--date"
        type={includeTime ? 'datetime-local' : 'date'}
        value={value}
        onChange={e => onChange(e.target.value)}
        min={min}
        max={max}
        aria-invalid={error ? true : undefined}
        aria-describedby={error ? `${id}-error` : undefined}
      />
    </FormField>
  );
}
```

**FormDropdown:**
```typescript
export interface FormDropdownOption {
  label: string;
  value: string;
}

interface FormDropdownProps {
  label: string;
  value: string;
  onChange: (value: string) => void;
  options: FormDropdownOption[];
  placeholder?: string;
  description?: string;
  error?: string;
}
```

**Form Container:**
```typescript
interface FormProps {
  children: ReactNode;
  onSubmit?: () => void;
}

export function Form({ children, onSubmit }: FormProps) {
  function handleKeyDown(e: React.KeyboardEvent) {
    if (e.key === 'Enter' && e.metaKey && onSubmit) {
      e.preventDefault();
      onSubmit();
    }
  }

  return (
    <form className="form" onSubmit={e => e.preventDefault()} onKeyDown={handleKeyDown} noValidate>
      <div className="form__fields">{children}</div>
    </form>
  );
}
```

### For Reminders Form:
You'll use:
- **FormTextField** for title
- **FormDatePicker** for due date
- **FormDatePicker** with `includeTime={true}` for due time (or separate time input)
- **FormDropdown** for repeat option (none/daily/weekly/monthly)
- **FormTextArea** for notes

