        showHUD({
          icon: <NoteHUDIcon />,
          title: 'Note Deleted',
        });
      },
    },
    dismissAction: { label: 'Cancel', style: 'cancel', onAction: () => {} },
  });
}, [selectedEntry, confirmAlert, showHUD, invalidateFts]);
