  onClick?: () => void;
  submenu?: DropdownSection[];
}

export interface DropdownSection {
  title?: string;
  actions: DropdownAction[];
}
```

**Building Dropdown Sections:**
```typescript
const dropdownSections: DropdownSection[] = useMemo(
  () => [
    {
      title: 'Actions',
      actions: [
        {
          label: 'Insert',
          shortcut: <Kbd keys={['↵']} />,
          onClick: handleInsert,
        },
        createCopyAction(
          {
            content: selectedEntry?.content ?? '',
            title: 'Copy',
            shortcut: <Kbd keys={['⌘', 'C']} />,
            hudIcon: <SnippetHUDIcon />,
          },
          showHUD,
        ),
        {
          label: 'Edit',
          shortcut: <Kbd keys={['⌘', 'E']} />,
          onClick: handleEdit,
        },
        {
          label: 'Create Snippet',
          shortcut: <Kbd keys={['⌘', 'N']} />,
          onClick: handleCreate,
        },
      ],
    },
    {
      title: 'Danger Zone',
      actions: [
        {
          label: 'Delete',
          shortcut: <Kbd keys={['⌘', '⌫']} />,
          onClick: handleDelete,
        },
      ],
    },
  ],
  [
    selectedEntry?.content,
    handleInsert,
    handleEdit,
    handleCreate,
    handleDelete,
    showHUD,
  ],
);
```

**Render in ActionPanel:**
```typescript
<ActionPanel
  contextLabel="Snippets"
  actions={[
    { label: 'Insert', shortcut: <Kbd keys={['↵']} /> },
    { label: 'Actions', shortcut: <Kbd keys={['⌘', 'K']} />, onClick: toggleActions },
  ]}
  dropdownOpen={actionsOpen}
  dropdownSections={dropdownSections}
  onDropdownClose={closeActions}
/>
```

---

### 9. **DELETE WITH CONFIRMATION**

**Alert Pattern:**
```typescript
const handleDelete = useCallback(() => {
  if (!selectedEntry) return;
  const entryId = selectedEntry.id;
  const entryName = selectedEntry.name;

  setActionsOpen(false);

  confirmAlert({
    title: `Delete "${entryName}"?`,
    message: 'This snippet will be permanently deleted.',
    icon: <svg>{/* trash icon */}</svg>,
    primaryAction: {
      label: 'Delete',
      style: 'destructive',
      onAction: () => {
        setEntries(prev => prev.filter(e => e.id !== entryId));
        snippetDb.delete(entryId).catch(console.error);
        invalidateFts();
        showHUD({
          icon: <SnippetHUDIcon />,
          title: 'Deleted',
        });
      },
    },
    dismissAction: {
      label: 'Cancel',
      style: 'cancel',
      onAction: () => {},
    },
  });
}, [selectedEntry, confirmAlert, showHUD, invalidateFts]);
```

---

### 10. **EXTENSION REGISTRATION**

**Manifest Pattern:** `/Users/anotonio.silva/antonio/lol/src/extensions/snippets/manifest.ts`

```typescript
import { SnippetsIcon } from '../../components/icons';
import { SnippetManagerView } from '../../components/snippet_manager/snippet_manager_view';
import type { ExtensionManifest } from '../../registry/types';

export const snippetsExtension: ExtensionManifest = {
  id: 'snippets',
  name: 'Snippets',
  icon: SnippetsIcon(),
  description:
    'Quickly find and insert your saved text snippets. Create shortcuts for frequently typed text.',
  author: 'Raycast',
  commands: [
    {
      name: 'snippets',
      title: 'Search Snippets',
      subtitle: 'Search Snippets',
      icon: SnippetsIcon(),
      keywords: ['snippet', 'text', 'expand', 'template'],
      mode: 'view',
      component: SnippetManagerView,
      fullView: true,
      section: 'Suggestions',
      accessories: [
        { date: new Date(Date.now() - 1000 * 60 * 60 * 3) },
        { text: 'Raycast' },
      ],
      detail: {
        markdown: `# Search Snippets\n\n...`,
        metadata: [
          { type: 'label', title: 'Application', text: 'Raycast' },
          { type: 'label', title: 'Type', text: 'Command' },
        ],
      },
    },
  ],
};
```

**Registration:** `/Users/anotonio.silva/antonio/lol/src/extensions/index.ts`

```typescript
import { registerExtension } from '../registry/command_registry';
import { snippetsExtension } from './snippets/manifest';

registerExtension(snippetsExtension);
```

---

### 11. **LIST RENDERING WITH SECTIONS**

**List Item with Accessories:**
```typescript
<ListItem
  key={entry.id}
  index={idx}
  icon={<SnippetHUDIcon />}
  title={entry.name}
  subtitle={truncateContent(entry.content, 50)}
  accessories={[
    // Keyword badge
    ...(entry.keyword
      ? [
          {
            tag: {
              text: entry.keyword,
              color: 'purple' as const,
            },
          },
        ]
      : []),
    // Tag badges
    ...entry.tags.map(t => ({
      tag: {
        text: t.text,
        color: t.color,
      },
    })),
    // Date
    {
      text: formatRelativeDate(entry.createdAt, now),
      tooltip: entry.createdAt.toLocaleString(),
    },
  ]}
  query={query || undefined}
/>
```

**List Section Structure:**
```typescript
{groupedByCategory.map(group => (
  <ListSection key={group.title} title={group.title}>
    {group.items.map((entry, idx) => (
      <ListItem key={entry.id} /* ... */ />
    ))}
  </ListSection>
))}
```

---

### 12. **HUD (HEADS-UP DISPLAY) NOTIFICATIONS**

**Hook Usage:**
```typescript
const { items: hudItems, show: showHUD } = useHUD();
```

**Showing HUD:**
```typescript
showHUD({
  icon: <SnippetHUDIcon />,
  title: 'Copied to Clipboard',
});
```

**Rendering:**
```typescript
<HUDContainer items={hudItems} />
```

---

### 13. **FORM SUB-VIEW RENDERING**

**Conditional Sub-view Rendering:**
```typescript
if (subView !== 'list') {
  const formTitle = subView === 'edit' ? 'Edit Snippet' : 'Create Snippet';

  return (
    <>
      <SearchBar
        value=""
        onChange={() => {}}
        placeholder={formTitle}
        breadcrumbs={[
          ...nav.breadcrumbs,
          {
            label: 'Snippets',
            onBack: handleEscape,
          },
        ]}
      />
      <div className="command-palette__body">
        <div className="command-palette__list-container">
          <EditSnippetView
            snippet={subView === 'edit' ? editingSnippet : undefined}
            onSubmit={handleFormSubmit}
          />
        </div>
      </div>
      <ActionPanel
        contextLabel={formTitle}
        actions={[
          {
            label: 'Submit',
            shortcut: <Kbd keys={['⌘', '↵']} />,
          },
        ]}
        dropdownOpen={false}
        dropdownSections={[]}
        onDropdownClose={() => {}}
      />
      <HUDContainer items={hudItems} />
    </>
  );
}
```

---

## KEY IMPLEMENTATION INSIGHTS

1. **Tag Management**: Tags are stored as `{ text: string, color?: TagColor }[]` in memory, serialized to JSON in DB
2. **Category Filter**: All items + category options in SearchDropdown; `filterValue !== 'all'` gate
3. **FTS Integration**: `useDbSearch` hook handles async search; results override fuzzy matching
4. **Form Tag Values**: Form uses tag value strings, converts back to objects with colors on submit
5. **Bidirectional Conversion**: `rowToEntry` / `entryToRow` for database persistence
6. **Keyboard Flow**: `Escape` cancels form → `Cmd+Enter` submits → handlers manage state transitions
7. **Breadcrumbs**: Dynamic breadcrumbs with `onBack` callbacks for nested navigation
8. **Empty States**: Shows message "Create your first snippet with ⌘N" or "Try a different search term"
9. **No Comments**: Code is self-explanatory; only JSDoc for public APIs
10. **Strict TypeScript**: All types validated; discriminated unions for sub-views

This is production-quality code with proper state management, accessibility, and error handling throughout.

