@use '../../styles/tokens';

.notes-editor {
  display: flex;
  flex-direction: column;
  flex: 1;
  padding: tokens.$space-3;
  gap: tokens.$space-3;
  overflow-y: auto;

  &__header {
    display: flex;
    align-items: center;
    gap: tokens.$space-2;
  }

  &__title-input {
    flex: 1;
    background: transparent;
    border: none;
    outline: none;
    font-family: tokens.$font-family;
    font-size: tokens.$font-lg;
    font-weight: tokens.$font-weight-medium;
    color: var(--color-text-primary);
    padding: tokens.$space-1 0;

    &::placeholder {
      color: var(--text-400);
    }
  }

  &__preview-toggle {
    flex-shrink: 0;
    background: var(--border-100);
    border: none;
    border-radius: tokens.$radius-md;
    padding: tokens.$space-1 tokens.$space-2;
    font-family: tokens.$font-family;
    font-size: tokens.$font-xs;
    font-weight: tokens.$font-weight-medium;
    color: var(--text-600);
    cursor: pointer;
    transition:
      background-color tokens.$transition-fast ease,
      color tokens.$transition-fast ease;

    &:hover {
      background: var(--border-200);
      color: var(--color-text-primary);
    }

    &:focus-visible {
      outline: 2px solid var(--color-accent);
      outline-offset: 1px;
    }

    &--active {
      background: var(--color-accent);
      color: #fff;

      &:hover {
        background: var(--color-accent-hover);
        color: #fff;
      }
    }
  }

  &__content-area {
    flex: 1;
    width: 100%;
    background: transparent;
    border: none;
    outline: none;
    font-family: tokens.$font-family-mono;
    font-size: tokens.$font-md;
    color: var(--color-text-primary);
    resize: none;
    line-height: 1.6;
    min-height: 200px;

    &::placeholder {
      color: var(--text-400);
    }
  }

  &__preview {
    flex: 1;
    overflow-y: auto;
    min-height: 200px;
  }

  &__meta {
    display: flex;
    align-items: center;
    gap: tokens.$space-2;
    font-size: tokens.$font-xs;
    color: var(--text-400);
    padding-top: tokens.$space-1;
    border-top: 1px solid var(--border-100);
  }
}

