export type RepeatOption = 'none' | 'daily' | 'weekly' | 'monthly';

export interface ReminderEntry {
  id: string;
  title: string;
  dueDate: Date;
  dueTime: string;
  repeat: RepeatOption;
  notes: string;
  completed: boolean;
  completedAt: Date | null;
  createdAt: Date;
}

export const REPEAT_OPTIONS: { label: string; value: RepeatOption }[] = [
  { label: 'None', value: 'none' },
  { label: 'Daily', value: 'daily' },
  { label: 'Weekly', value: 'weekly' },
  { label: 'Monthly', value: 'monthly' },
];

export function isRepeatOption(v: string): v is RepeatOption {
  return v === 'none' || v === 'daily' || v === 'weekly' || v === 'monthly';
}

const today = new Date();
today.setHours(0, 0, 0, 0);

function daysFromNow(days: number): Date {
  const d = new Date(today);
  d.setDate(d.getDate() + days);
  return d;
}

