      return;
    }
    const all = await this.getAll();
    storageSet(
      'snippets',
      all.filter(r => r.id !== id),
    );
  },
  async search(query: string, limit = 50): Promise<SnippetRow[]> {
    if (isTauri) {
      const escaped = escapeFts5Query(query);
      if (!escaped) return [];
