import { isTauri } from '../platform';
import {
  isStringArray,
  storageGet,
  storageRemove,
  storageSet,
} from './storage';

const DB_PATH = 'sqlite:raycast_clone.db';

export interface ClipboardEntryRow {
  id: string;
  content: string;
  content_type: string;
  source_app: string;
  copied_at: string;
  pinned: number;
}

export interface SnippetRow {
  id: string;
  name: string;
  keyword: string;
  content: string;
  category: string;
  tags: string;
  created_at: string;
}

export interface QuicklinkRow {
  id: string;
  name: string;
  link: string;
  type: string;
  application: string | null;
  tags: string;
  created_at: string;
}

export interface NoteRow {
  id: string;
  title: string;
  content: string;
  created_at: string;
  updated_at: string;
}

export interface ReminderRow {
  id: string;
  title: string;
  due_date: string;
  due_time: string;
  repeat: string;
  notes: string;
  completed: number;
  completed_at: string | null;
  created_at: string;
}

export interface RecentCommandRow {
  id: number;
  command_id: string;
  used_at: string;
}

export interface SettingRow {
  key: string;
  value: string;
}

type DatabaseInstance = {
  execute(
    query: string,
    bindValues?: unknown[],
  ): Promise<{ rowsAffected: number }>;
  select<T>(query: string, bindValues?: unknown[]): Promise<T>;
};

let dbInstance: DatabaseInstance | undefined;
let dbPromise: Promise<DatabaseInstance> | undefined;

async function loadDb(): Promise<DatabaseInstance> {
  const Database = (await import('@tauri-apps/plugin-sql')).default;
  return Database.load(DB_PATH);
}

function getDb(): Promise<DatabaseInstance> {
  if (dbInstance) return Promise.resolve(dbInstance);
  if (dbPromise) return dbPromise;

  dbPromise = loadDb()
    .then(db => {
      dbInstance = db;
      return db;
    })
    .catch(err => {
      dbPromise = undefined;
      throw err;
    });

  return dbPromise;
}

const CLIPBOARD_COLUMNS = new Set<string>([
  'content',
  'content_type',
  'source_app',
  'copied_at',
  'pinned',
]);

const SNIPPET_COLUMNS = new Set<string>([
  'name',
  'keyword',
  'content',
  'category',
  'tags',
  'created_at',
]);

const QUICKLINK_COLUMNS = new Set<string>([
  'name',
  'link',
  'type',
  'application',
  'tags',
  'created_at',
]);

const NOTE_COLUMNS = new Set<string>([
  'title',
  'content',
  'created_at',
]);

const REMINDER_COLUMNS = new Set<string>([
  'title',
  'due_date',
  'due_time',
  'repeat',
  'notes',
  'completed',
  'completed_at',
  'created_at',
]);

function buildUpdateQuery(
  table: string,
  updates: Record<string, unknown>,
  allowedColumns: Set<string>,
  id: string
): {
  sql: string;
  values: unknown[];
} | null {
  const fields: string[] = [];
  const values: unknown[] = [];
  let idx = 1;

  for (const [key, value] of Object.entries(updates)) {
    if (!allowedColumns.has(key)) continue;
    fields.push(`${key} = $${idx}`);
    values.push(value);
    idx++;
  }

  if (fields.length === 0) return null;
  values.push(id);
  return {
    sql: `UPDATE ${table} SET ${fields.join(', ')} WHERE id = $${idx}`,
    values,
  };
}

function escapeLikeQuery(query: string): string {
  return query.replace(/[\\%_]/g, ch => `\\${ch}`);
}

function escapeFts5Query(query: string): string {
  return query
    .split(/\s+/)
    .filter(Boolean)
    .map(token => `"${token.replace(/"/g, '""')}"`)
    .join(' ');
}

function isClipboardRowArray(v: unknown): v is ClipboardEntryRow[] {
  if (!Array.isArray(v)) return false;
  return v.every(
    r =>
      typeof r === 'object' &&
      r !== null &&
      'id' in r &&
      typeof r.id === 'string' &&
      'content' in r &&
      typeof r.content === 'string' &&
      'copied_at' in r &&
      typeof r.copied_at === 'string',
  );
}

function isSnippetRowArray(v: unknown): v is SnippetRow[] {
  if (!Array.isArray(v)) return false;
