import { isTauri } from '../platform';
import {
  isStringArray,
  storageGet,
  storageRemove,
  storageSet,
} from './storage';

const DB_PATH = 'sqlite:raycast_clone.db';

export interface ClipboardEntryRow {
  id: string;
  content: string;
  content_type: string;
  source_app: string;
  copied_at: string;
  pinned: number;
}

export interface SnippetRow {
  id: string;
  name: string;
  keyword: string;
  content: string;
  category: string;
  tags: string;
  created_at: string;
}

export interface QuicklinkRow {
  id: string;
  name: string;
  link: string;
  type: string;
  application: string | null;
  tags: string;
  created_at: string;
}

export interface NoteRow {
  id: string;
  title: string;
  content: string;
  created_at: string;
  updated_at: string;
}

export interface ReminderRow {
  id: string;
